#define OSKERNEL_WATCHDOG_SECONDS    600U
#define SBI_EXT_SRST                 0x53525354UL
#define SBI_SRST_SYSTEM_RESET        0UL
#define SBI_RESET_TYPE_SHUTDOWN      0UL
#define SBI_RESET_TYPE_COLD_REBOOT   1UL
#define SBI_RESET_TYPE_WARM_REBOOT   2UL
#define SBI_RESET_REASON_NONE        0UL
#define SBI_LEGACY_SHUTDOWN          8UL

static long qemu_virt_sbi_call(rt_ubase_t ext, rt_ubase_t fid,
                               rt_ubase_t arg0, rt_ubase_t arg1)
{
    register rt_ubase_t a0 __asm("a0") = arg0;
    register rt_ubase_t a1 __asm("a1") = arg1;
    register rt_ubase_t a6 __asm("a6") = fid;
    register rt_ubase_t a7 __asm("a7") = ext;

    __asm__ volatile("ecall"
                     : "+r"(a0), "+r"(a1)
                     : "r"(a6), "r"(a7)
                     : "memory");
    return (long)a0;
}

static void qemu_virt_sbi_srst(rt_ubase_t reset_type)
{
    (void)qemu_virt_sbi_call(SBI_EXT_SRST, SBI_SRST_SYSTEM_RESET,
                             reset_type, SBI_RESET_REASON_NONE);
}

static void qemu_virt_sbi_legacy_poweroff(void)
{
    (void)qemu_virt_sbi_call(SBI_LEGACY_SHUTDOWN, 0, 0, 0);
}

static void qemu_virt_finisher_poweroff(void)
{
    volatile rt_uint32_t *finisher = (volatile rt_uint32_t *)0x100000;

    *finisher = 0x5555;
    __asm__ volatile("fence iorw, iorw" ::: "memory");
}

static void qemu_virt_poweroff(void)
{
    rt_kprintf("[power] requesting qemu reset/shutdown\n");
    rt_hw_interrupt_disable();
    while (1)
    {
        qemu_virt_sbi_srst(SBI_RESET_TYPE_COLD_REBOOT);
        qemu_virt_sbi_srst(SBI_RESET_TYPE_WARM_REBOOT);
        qemu_virt_sbi_srst(SBI_RESET_TYPE_SHUTDOWN);
        qemu_virt_sbi_legacy_poweroff();
        qemu_virt_finisher_poweroff();
    }
}

static void qemu_shutdown_watchdog(void *parameter)
{
    RT_UNUSED(parameter);

    rt_thread_mdelay(OSKERNEL_WATCHDOG_SECONDS * 1000U);
    rt_kprintf("[power] watchdog timeout after %u seconds\n",
               OSKERNEL_WATCHDOG_SECONDS);
    qemu_virt_poweroff();
}

static void start_shutdown_watchdog(void)
{
    rt_thread_t watchdog;

    watchdog = rt_thread_create("ojwd", qemu_shutdown_watchdog, RT_NULL,
                                4096, 3, 10);
    if (watchdog != RT_NULL)
    {
        rt_thread_startup(watchdog);
    }
    else
    {
        rt_kprintf("[power] failed to start shutdown watchdog\n");
    }
}

int main(void)
{
    rt_kprintf("OSKernel2026-X RISC-V boot\n");
    start_shutdown_watchdog();
    oskernel_real_run_tests();
    qemu_virt_poweroff();

    return 0;
}

