static int is_space(char ch)
{
    return ch == ' ' || ch == '\t' || ch == '\r' || ch == '\n';
}

static int str_eq(const char *a, const char *b)
{
    while (*a != '\0' && *b != '\0')
    {
        if (*a != *b)
        {
            return 0;
        }
        a++;
        b++;
    }

    return *a == '\0' && *b == '\0';
}

static int starts_with(const char *s, const char *prefix)
{
    while (*prefix != '\0')
    {
        if (*s++ != *prefix++)
        {
            return 0;
        }
    }

    return 1;
}

static const char *find_char(const char *s, char target)
{
    while (s != RT_NULL && *s != '\0')
    {
        if (*s == target)
        {
            return s;
        }
        s++;
    }
    return RT_NULL;
}

static rt_size_t string_length(const char *s)
{
    rt_size_t len = 0;

    while (s != RT_NULL && s[len] != '\0')
    {
        len++;
    }
    return len;
}

static void copy_string(char *dst, rt_size_t dst_size, const char *src)
{
    rt_size_t i = 0;

    if (dst_size == 0)
    {
        return;
    }
    while (src != RT_NULL && i + 1 < dst_size && src[i] != '\0')
    {
        dst[i] = src[i];
        i++;
    }
    dst[i] = '\0';
}

static int ends_with(const char *s, const char *suffix)
{
    rt_size_t s_len = string_length(s);
    rt_size_t suffix_len = string_length(suffix);

    if (suffix_len > s_len)
    {
        return 0;
    }
    return str_eq(s + s_len - suffix_len, suffix);
}

static int remove_last_component(char *path)
{
    rt_size_t len = string_length(path);

    while (len > 0 && path[len - 1] == '/')
    {
        path[--len] = '\0';
    }
    while (len > 0 && path[len - 1] != '/')
    {
        path[--len] = '\0';
    }
    if (len > 0 && path[len - 1] == '/')
    {
        path[len - 1] = '\0';
    }
    return 0;
}

