static rt_uint16_t le16(const rt_uint8_t *p)
{
    return (rt_uint16_t)p[0] | ((rt_uint16_t)p[1] << 8);
}

static rt_uint32_t le32(const rt_uint8_t *p)
{
    return (rt_uint32_t)p[0] |
           ((rt_uint32_t)p[1] << 8) |
           ((rt_uint32_t)p[2] << 16) |
           ((rt_uint32_t)p[3] << 24);
}

static int read_bytes(rt_device_t dev, rt_uint64_t offset, void *buffer, rt_size_t size)
{
    rt_uint8_t sector[SECTOR_SIZE];
    rt_uint8_t *out = (rt_uint8_t *)buffer;

    while (size > 0)
    {
        rt_uint32_t inner = (rt_uint32_t)(offset % SECTOR_SIZE);
        rt_size_t chunk = SECTOR_SIZE - inner;

        if (chunk > size)
        {
            chunk = size;
        }

        if (rt_device_read(dev, (rt_off_t)(offset / SECTOR_SIZE), sector, 1) != 1)
        {
            return -1;
        }

        rt_memcpy(out, sector + inner, chunk);
        out += chunk;
        offset += chunk;
        size -= chunk;
    }

    return 0;
}

