static rt_uint64_t page_down(rt_uint64_t value)
{
    return value & ~(OS_PAGE_SIZE - 1ULL);
}

static rt_uint64_t page_up(rt_uint64_t value)
{
    return (value + OS_PAGE_SIZE - 1ULL) & ~(OS_PAGE_SIZE - 1ULL);
}

static rt_uint64_t sv39_pte(rt_uint64_t pa, rt_uint64_t flags)
{
    return ((pa >> 12) << 10) | flags;
}

static rt_uint32_t sv39_index(rt_uint64_t va, unsigned int shift)
{
    return (rt_uint32_t)((va >> shift) & 0x1ffULL);
}

static rt_uint8_t *alloc_aligned_page(struct os_user_page_pool *pool)
{
    rt_uintptr_t aligned;
    rt_uint8_t *raw;

    if (pool->count >= OS_MAX_ALLOC_PAGES)
    {
        return RT_NULL;
    }

    raw = (rt_uint8_t *)rt_malloc((rt_size_t)(OS_PAGE_SIZE * 2));
    if (raw == RT_NULL)
    {
        return RT_NULL;
    }

    aligned = ((rt_uintptr_t)raw + OS_PAGE_SIZE - 1U) & ~(rt_uintptr_t)(OS_PAGE_SIZE - 1U);
    pool->raw[pool->count] = raw;
    pool->page[pool->count] = (rt_uint8_t *)aligned;
    pool->count++;

    rt_memset((void *)aligned, 0, (rt_size_t)OS_PAGE_SIZE);
    return (rt_uint8_t *)aligned;
}

static void free_page_pool(struct os_user_page_pool *pool)
{
    rt_uint32_t i;

    for (i = 0; i < pool->count; ++i)
    {
        rt_free(pool->raw[i]);
        pool->raw[i] = RT_NULL;
        pool->page[i] = RT_NULL;
    }
    pool->count = 0;
}

static rt_uint64_t *ensure_next_table(rt_uint64_t *entry,
                                      struct os_user_page_pool *pool)
{
    rt_uint8_t *page;

    if ((*entry & PTE_V) != 0)
    {
        if ((*entry & (PTE_R | PTE_W | PTE_X)) != 0)
        {
            return RT_NULL;
        }
        return (rt_uint64_t *)(((*entry) >> 10) << 12);
    }

    page = alloc_aligned_page(pool);
    if (page == RT_NULL)
    {
        return RT_NULL;
    }

    *entry = sv39_pte((rt_uint64_t)(rt_uintptr_t)page, PTE_V);
    return (rt_uint64_t *)page;
}

static int map_page(rt_uint64_t *root, struct os_user_page_pool *pool,
