static int kernel_str_ends(const char *s, const char *suffix)
{
    rt_size_t s_len = kernel_strlen(s);
    rt_size_t suffix_len = kernel_strlen(suffix);

    if (suffix_len > s_len)
    {
        return 0;
    }
    return kernel_str_eq(s + s_len - suffix_len, suffix);
}

