static void pipe_note_close(struct os_fd *entry)
{
    struct os_pipe *pipe;

    if (entry->mem_index < 0 || (unsigned int)entry->mem_index >= OS_MAX_PIPES)
    {
        return;
    }

    pipe = &g_pipes[entry->mem_index];
    if (!pipe->used)
    {
        return;
    }
    if (entry->type == OS_FD_PIPE_READ)
    {
        pipe->reader_open = 0;
    }
    else if (entry->type == OS_FD_PIPE_WRITE)
    {
        pipe->writer_open = 0;
    }
}

static void runtime_close_fd(unsigned int fd)
{
    struct os_fd *entry;

    if (fd >= OS_MAX_FD)
    {
        return;
    }

    entry = &g_fd_table[fd];
    if (entry->type == OS_FD_EXT4_FILE)
    {
        judge_ext4_free_file(&entry->file);
    }
    else if (entry->type == OS_FD_PIPE_READ || entry->type == OS_FD_PIPE_WRITE)
    {
        pipe_note_close(entry);
    }
    rt_memset(entry, 0, sizeof(*entry));
}

