static int alloc_fd_from(unsigned int start)
{
    unsigned int i;
    unsigned int limit = (unsigned int)g_fd_limit;

    if (start >= OS_MAX_FD)
    {
        return -1;
    }
    if (limit == 0 || limit > OS_MAX_FD)
    {
        limit = OS_MAX_FD;
    }

    for (i = start; i < limit; ++i)
    {
        if (g_fd_table[i].type == OS_FD_FREE)
        {
            return (int)i;
        }
    }

    return -1;
}

