static void copy_kernel_string(char *dst, rt_size_t dst_size, const char *src)
{
    rt_size_t i = 0;

    if (dst_size == 0)
    {
        return;
    }

    while (i + 1 < dst_size && src[i] != '\0')
    {
        dst[i] = src[i];
        i++;
    }
    dst[i] = '\0';
}

static int normalize_path_to(char *out, rt_size_t out_size, int dirfd, const char *input)
{
    char tmp[OS_PATH_MAX];
    char base[OS_PATH_MAX];
    const char *p;
    rt_size_t len = 0;

    if (out == RT_NULL || input == RT_NULL || out_size == 0)
    {
        return -1;
    }

    base[0] = '\0';
    if (input[0] != '/')
    {
        if (dirfd >= 0 && (unsigned int)dirfd < OS_MAX_FD &&
            g_fd_table[dirfd].type == OS_FD_DIR)
        {
            copy_kernel_string(base, sizeof(base), g_fd_table[dirfd].path);
        }
        else if (!kernel_str_eq(g_cwd, "/"))
        {
            copy_kernel_string(base, sizeof(base), g_cwd + 1);
        }
    }

    p = input;
    while (*p == '/')
    {
        p++;
    }
    while (p[0] == '.' && p[1] == '/')
    {
        p += 2;
        while (*p == '/')
        {
            p++;
        }
    }
    if (p[0] == '.' && p[1] == '\0')
    {
        p++;
    }

    if (base[0] != '\0')
    {
        rt_size_t i = 0;

        while (base[i] != '\0' && len + 1 < sizeof(tmp))
        {
            tmp[len++] = base[i++];
        }
        if (len > 0 && tmp[len - 1] != '/' && len + 1 < sizeof(tmp) && *p != '\0')
        {
            tmp[len++] = '/';
        }
    }

    while (*p != '\0' && len + 1 < sizeof(tmp))
    {
        if (*p == '/' && len > 0 && tmp[len - 1] == '/')
        {
            p++;
            continue;
        }
        tmp[len++] = *p++;
    }
    tmp[len] = '\0';

    if (tmp[0] == '\0')
    {
        copy_kernel_string(out, out_size, ".");
    }
    else
    {
        copy_kernel_string(out, out_size, tmp);
    }
    return 0;
}

static int find_mem_file(const char *path)
{
    unsigned int i;

    for (i = 0; i < OS_MAX_MEM_FILES; ++i)
    {
        if (g_mem_files[i].used && !g_mem_files[i].removed &&
            kernel_str_eq(g_mem_files[i].path, path))
        {
            return (int)i;
        }
    }

    return -1;
}

static int find_removed_mem_file(const char *path)
{
    unsigned int i;

    for (i = 0; i < OS_MAX_MEM_FILES; ++i)
    {
        if (g_mem_files[i].used && g_mem_files[i].removed &&
            kernel_str_eq(g_mem_files[i].path, path))
        {
            return (int)i;
        }
    }

    return -1;
}

static int create_mem_file(const char *path, int is_dir)
{
    unsigned int i;

    for (i = 0; i < OS_MAX_MEM_FILES; ++i)
    {
        if (!g_mem_files[i].used ||
            (g_mem_files[i].removed && kernel_str_eq(g_mem_files[i].path, path)))
        {
            g_mem_files[i].used = 1;
            g_mem_files[i].is_dir = is_dir;
            g_mem_files[i].removed = 0;
            g_mem_files[i].size = 0;
            if (g_mem_files[i].data != RT_NULL)
            {
                rt_free(g_mem_files[i].data);
                g_mem_files[i].data = RT_NULL;
            }
            g_mem_files[i].capacity = 0;
            g_mem_files[i].atime_sec = (rt_int64_t)(g_fake_usec / 1000000ULL);
            g_mem_files[i].atime_nsec = 0;
            g_mem_files[i].mtime_sec = g_mem_files[i].atime_sec;
            g_mem_files[i].mtime_nsec = 0;
            copy_kernel_string(g_mem_files[i].path, sizeof(g_mem_files[i].path), path);
            return (int)i;
        }
    }

    return -1;
}

static int ensure_text_mem_file(const char *path, const char *content)
{
    int index = find_mem_file(path);
    rt_size_t len;

    if (index < 0)
    {
        index = create_mem_file(path, 0);
    }
    if (index < 0)
    {
        return -1;
    }

    len = kernel_strlen(content);
    if (ensure_mem_capacity(&g_mem_files[index], len) != 0)
    {
        return -1;
    }
    rt_memcpy(g_mem_files[index].data, content, len);
    g_mem_files[index].size = len;
    return index;
}

