static int inspect_script_file(const char *abi, const char *script_name,
                               const char *cwd, int run_mode,
                               unsigned int depth)
{
    struct judge_ext4_file script;
    int executed;

    if (depth > SCRIPT_RECURSION_LIMIT)
    {
        rt_kprintf("[runner] script recursion too deep at /%s/%s\n",
                   abi, script_name);
        return 0;
    }
    if (judge_ext4_read_file(abi, script_name, SCRIPT_READ_LIMIT, &script) != 0)
    {
        return -1;
    }

    rt_kprintf("[runner] found script /%s/%s: read=%u total=%u\n",
               abi, script_name, (rt_uint32_t)script.size,
               (rt_uint32_t)script.total_size);
