static int inspect_one_script(const char *abi, const char *script_name)
{
    int run_mode = RUN_MODE_PREVIEW;
    int executed;

    if (str_eq(script_name, "oskernel_user_smoke.sh"))
    {
        run_mode = RUN_MODE_SMOKE;
    }
    else if (str_eq(script_name, "basic_testcode.sh"))
    {
        run_mode = RUN_MODE_BASIC;
        basic_exec_count = 0;
        basic_exec_limit = BASIC_EXEC_LIMIT_PER_ABI;
    }
    else if (str_eq(script_name, "busybox_testcode.sh"))
    {
        return run_busybox_command_list(abi) > 0 ? 1 : 0;
    }
    else if (str_eq(script_name, "lua_testcode.sh"))
    {
        run_mode = RUN_MODE_LUA;
    }
    else if (str_eq(script_name, "libcbench_testcode.sh"))
    {
        run_mode = RUN_MODE_EXEC;
    }
    else if (str_eq(script_name, "iozone_testcode.sh"))
    {
        run_mode = RUN_MODE_EXEC;
    }
    else if (str_eq(script_name, "libctest_testcode.sh"))
    {
        return run_libctest_group(abi) > 0 ? 1 : 0;
    }
    else
    {
        return 0;
    }

    executed = inspect_script_file(abi, script_name, "", run_mode, 0);
    if (run_mode == RUN_MODE_BASIC)
    {
        basic_exec_limit = 0;
    }
    if (executed < 0)
    {
        return 0;
    }
    if (run_mode == RUN_MODE_SMOKE && executed)
    {
        return 2;
    }
    return 1;
}

int oskernel_real_run_tests(void)
{
    static const char *abis[] = { "glibc", "musl" };
    static const char *scripts[] = {
        "basic_testcode.sh",
        "busybox_testcode.sh",
        "libctest_testcode.sh",
    };
    rt_size_t abi_index;
    rt_size_t script_index;
    int found = 0;
    int script_available[sizeof(abis) / sizeof(abis[0])]
                        [sizeof(scripts) / sizeof(scripts[0])] = { { 0 } };

    rt_kprintf("[runner] real OS runner mode: legacy answer output is disabled\n");
    for (abi_index = 0; abi_index < sizeof(abis) / sizeof(abis[0]); ++abi_index)
    {
        for (script_index = 0; script_index < sizeof(scripts) / sizeof(scripts[0]); ++script_index)
        {
            script_available[abi_index][script_index] =
                judge_ext4_has_script(abis[abi_index], scripts[script_index]);
        }
    }

    for (abi_index = 0; abi_index < sizeof(abis) / sizeof(abis[0]); ++abi_index)
    {
        if (script_available[abi_index][1])
        {
            judge_ext4_cache_file(abis[abi_index], "busybox_cmd.txt",
                                  SCRIPT_READ_LIMIT);
        }
        if (script_available[abi_index][0])
        {
            prefetch_basic_for_abi(abis[abi_index]);
        }
    }

    for (script_index = 0; script_index < sizeof(scripts) / sizeof(scripts[0]); ++script_index)
    {
        for (abi_index = 0; abi_index < sizeof(abis) / sizeof(abis[0]); ++abi_index)
        {
            int result;

            if (!script_available[abi_index][script_index])
            {
                rt_kprintf("[runner] skip missing /%s/%s\n",
                           abis[abi_index], scripts[script_index]);
                continue;
            }
            result = inspect_one_script(abis[abi_index], scripts[script_index]);
            if (result == 2)
            {
                rt_kprintf("[runner] user-mode smoke completed; returning to main\n");
                return found + 1;
            }
            found += result;
        }
    }

    if (found == 0)
    {
        rt_kprintf("[runner] no judge test scripts found on virtio-blk0\n");
    }

    rt_kprintf("[runner] no testcase success lines are synthesized in this mode\n");
    rt_kprintf("[runner] local user-mode smoke entry: /glibc/oskernel_user_smoke.sh or /musl/oskernel_user_smoke.sh\n");
    return found;
}

