void handle_trap(rt_ubase_t scause, rt_ubase_t stval, rt_ubase_t sepc,
                 struct rt_hw_stack_frame *sp)
{
    ENTER_TRAP;
    rt_ubase_t id = __MASKVALUE(scause, __MASK(63UL));
    const char *msg;

    /* supervisor external interrupt */
    if ((SCAUSE_INTERRUPT & scause) &&
        SCAUSE_S_EXTERNAL_INTR == (scause & 0xff))
    {
        rt_interrupt_enter();
        plic_handle_irq();
        rt_interrupt_leave();
    }
    else if ((SCAUSE_INTERRUPT | SCAUSE_S_TIMER_INTR) == scause)
    {
        /* supervisor timer */
        rt_interrupt_enter();
        tick_isr();
        rt_interrupt_leave();
    }
#ifdef RT_USING_SMP
    else if ((SCAUSE_INTERRUPT | SCAUSE_S_SOFTWARE_INTR) == scause)
    {
        /* supervisor software interrupt for ipi */
        rt_interrupt_enter();
        rt_hw_ipi_handler();
        rt_interrupt_leave();
    }
#endif /* RT_USING_SMP */
    else
    {
