#define USER_PAGE_SIZE 4096ULL

static rt_uint64_t page_down(rt_uint64_t value)
{
    return value & ~(USER_PAGE_SIZE - 1ULL);
}

static rt_uint64_t page_up(rt_uint64_t value)
{
    return (value + USER_PAGE_SIZE - 1ULL) & ~(USER_PAGE_SIZE - 1ULL);
}

static rt_uint64_t find_phdr_vaddr(const struct os_elf_image *elf)
{
    rt_uint64_t phdr_size = (rt_uint64_t)elf->phentsize * elf->phnum;
    rt_uint32_t i;

    if (phdr_size == 0 || elf->phoff + phdr_size < elf->phoff)
    {
        return 0;
    }

    for (i = 0; i < elf->segment_count; ++i)
    {
        const struct os_elf_segment *seg = &elf->segments[i];

        if (elf->phoff >= seg->offset &&
            elf->phoff + phdr_size <= seg->offset + seg->filesz)
        {
            return seg->vaddr + (elf->phoff - seg->offset);
        }
    }

    return 0;
}

int os_user_image_build(const struct os_elf_image *elf, struct os_user_image *image)
{
    rt_uint32_t i;

    if (elf == RT_NULL || image == RT_NULL)
    {
        return -1;
    }

    rt_memset(image, 0, sizeof(*image));
    image->entry = elf->runtime_entry != 0 ? elf->runtime_entry : elf->entry;
    image->aux_entry = elf->entry;
    image->aux_base = elf->aux_base;
    image->phdr = find_phdr_vaddr(elf);
    image->phent = elf->phentsize;
    image->phnum = elf->phnum;
    image->low_vaddr = ~(rt_uint64_t)0;
    image->high_vaddr = 0;

    for (i = 0; i < elf->segment_count; ++i)
    {
        const struct os_elf_segment *seg = &elf->segments[i];
        struct os_user_mapping *map;
        rt_uint64_t start;
        rt_uint64_t end;
        rt_uint64_t page_offset;
        rt_uint64_t map_size;

        if (seg->memsz == 0)
        {
            continue;
        }
        if (image->mapping_count >= OS_USER_IMAGE_MAX_MAPPINGS)
        {
            os_user_image_destroy(image);
            return -1;
        }

        start = page_down(seg->vaddr);
        end = page_up(seg->vaddr + seg->memsz);
        page_offset = seg->vaddr - start;
        map_size = end - start;
        if (map_size == 0 || map_size > 32ULL * 1024ULL * 1024ULL)
        {
            os_user_image_destroy(image);
            return -1;
        }

        map = &image->mappings[image->mapping_count++];
        map->vaddr = start;
        map->size = map_size;
        map->flags = seg->flags;
        map->memory = (rt_uint8_t *)rt_malloc((rt_size_t)map_size);
        if (map->memory == RT_NULL)
        {
            os_user_image_destroy(image);
            return -1;
        }
        rt_memset(map->memory, 0, (rt_size_t)map_size);

        if (seg->filesz != 0)
        {
            if (seg->data == RT_NULL || page_offset + seg->filesz > map_size)
            {
                os_user_image_destroy(image);
                return -1;
            }
            rt_memcpy(map->memory + page_offset, seg->data, (rt_size_t)seg->filesz);
        }

        if (map->vaddr < image->low_vaddr)
        {
            image->low_vaddr = map->vaddr;
        }
        if (map->vaddr + map->size > image->high_vaddr)
        {
            image->high_vaddr = map->vaddr + map->size;
        }
    }

    return image->mapping_count > 0 ? 0 : -1;
}

void os_user_image_destroy(struct os_user_image *image)
{
    rt_uint32_t i;

    if (image == RT_NULL)
    {
        return;
    }

    for (i = 0; i < image->mapping_count; ++i)
    {
        if (image->mappings[i].memory != RT_NULL)
        {
            rt_free(image->mappings[i].memory);
            image->mappings[i].memory = RT_NULL;
        }
    }
    image->mapping_count = 0;
}

void os_user_image_dump(const char *abi, const char *path, const struct os_user_image *image)
{
