#include <rtthread.h>
#include "judge_ext4_scan.h"
#include "os_elf_loader.h"

#define EI_CLASS      4
#define EI_DATA       5
#define ELFCLASS64    2
#define ELFDATA2LSB   1
#define ET_EXEC       2
#define ET_DYN        3
#define EM_RISCV      243
#define PT_LOAD       1
#define PT_INTERP     3
#define PT_DYNAMIC    2
#define ELF_HDR_SIZE  64
#define PHDR_MAX_SIZE 4096

static rt_uint16_t rd16(const rt_uint8_t *p)
{
    return (rt_uint16_t)p[0] | ((rt_uint16_t)p[1] << 8);
}

static rt_uint32_t rd32(const rt_uint8_t *p)
{
    return (rt_uint32_t)p[0] |
           ((rt_uint32_t)p[1] << 8) |
           ((rt_uint32_t)p[2] << 16) |
           ((rt_uint32_t)p[3] << 24);
}

static rt_uint64_t rd64(const rt_uint8_t *p)
{
    return (rt_uint64_t)rd32(p) | ((rt_uint64_t)rd32(p + 4) << 32);
}

static void copy_string(char *dst, rt_size_t dst_size, const char *src, rt_size_t src_size)
{
    rt_size_t i;

    if (dst_size == 0)
    {
        return;
    }

    for (i = 0; i + 1 < dst_size && i < src_size && src[i] != '\0'; ++i)
    {
        dst[i] = src[i];
    }
    dst[i] = '\0';
}

static int read_file_region(const char *abi, const char *path, rt_uint64_t offset,
                            rt_size_t size, rt_uint8_t *out)
{
    struct judge_ext4_file prefix;

    if (offset + size < offset)
    {
        return -1;
    }

    if (judge_ext4_read_file(abi, path, (rt_size_t)(offset + size), &prefix) != 0)
    {
        return -1;
    }
    if (prefix.size < offset + size)
    {
        judge_ext4_free_file(&prefix);
        return -1;
    }

    rt_memcpy(out, (const rt_uint8_t *)prefix.data + offset, size);
    judge_ext4_free_file(&prefix);
    return 0;
}

static int load_segment_data(const char *abi, const char *path, struct os_elf_segment *seg)
{
    if (seg->filesz == 0)
    {
        seg->data = RT_NULL;
        return 0;
    }
    if (seg->filesz > 16U * 1024U * 1024U)
    {
        rt_kprintf("[elf] refusing huge segment filesz=%u\n", (rt_uint32_t)seg->filesz);
        return -1;
    }

    seg->data = (rt_uint8_t *)rt_malloc((rt_size_t)seg->filesz);
    if (seg->data == RT_NULL)
    {
        return -1;
    }

    if (read_file_region(abi, path, seg->offset, (rt_size_t)seg->filesz, seg->data) != 0)
    {
        rt_free(seg->data);
        seg->data = RT_NULL;
        return -1;
    }

    return 0;
}

static int parse_phdrs(const char *abi, const char *path, const rt_uint8_t *header,
                       rt_uint64_t total_size, struct os_elf_image *image)
{
    struct judge_ext4_file phdr_file;
    rt_uint8_t *phdrs;
    rt_uint64_t phdr_size;
    rt_uint16_t i;
    int ret = -1;

    image->phoff = rd64(header + 32);
    image->phentsize = rd16(header + 54);
    image->phnum = rd16(header + 56);
    if (image->phnum == 0 || image->phentsize < 56)
    {
        rt_kprintf("[elf] /%s/%s has no usable program headers\n", abi, path);
        return -1;
    }

    phdr_size = (rt_uint64_t)image->phentsize * image->phnum;
    if (image->phoff + phdr_size > total_size || phdr_size > PHDR_MAX_SIZE)
    {
        rt_kprintf("[elf] /%s/%s program headers out of range\n", abi, path);
        return -1;
    }

    if (judge_ext4_read_file(abi, path, (rt_size_t)(image->phoff + phdr_size), &phdr_file) != 0)
    {
        return -1;
    }
    if (phdr_file.size < image->phoff + phdr_size)
    {
        goto out;
    }

    phdrs = (rt_uint8_t *)phdr_file.data + image->phoff;
    image->low_vaddr = ~(rt_uint64_t)0;
    image->high_vaddr = 0;

    for (i = 0; i < image->phnum; ++i)
    {
        const rt_uint8_t *ph = phdrs + (rt_uint64_t)i * image->phentsize;
        rt_uint32_t type = rd32(ph);

        if (type == PT_INTERP)
        {
            rt_uint64_t off = rd64(ph + 8);
            rt_uint64_t filesz = rd64(ph + 32);
            char interp[128];

            if (filesz > 0 && filesz < sizeof(interp) &&
                off + filesz <= total_size &&
                read_file_region(abi, path, off, (rt_size_t)filesz,
                                 (rt_uint8_t *)interp) == 0)
            {
                copy_string(image->interp, sizeof(image->interp),
                            interp, (rt_size_t)filesz);
            }
        }
        else if (type == PT_DYNAMIC)
        {
            image->dynamic_vaddr = rd64(ph + 16);
            image->dynamic_size = rd64(ph + 32);
        }
        else if (type == PT_LOAD)
        {
            struct os_elf_segment *seg;

            if (image->segment_count >= OS_ELF_MAX_SEGMENTS)
            {
                rt_kprintf("[elf] /%s/%s has too many LOAD segments\n", abi, path);
                goto out;
            }

            seg = &image->segments[image->segment_count++];
            seg->flags = rd32(ph + 4);
            seg->offset = rd64(ph + 8);
            seg->vaddr = rd64(ph + 16);
            seg->filesz = rd64(ph + 32);
            seg->memsz = rd64(ph + 40);
            seg->data = RT_NULL;

            if (seg->filesz > seg->memsz || seg->offset + seg->filesz > total_size)
            {
                rt_kprintf("[elf] /%s/%s LOAD segment out of range\n", abi, path);
                goto out;
            }
            if (seg->vaddr < image->low_vaddr)
            {
                image->low_vaddr = seg->vaddr;
            }
            if (seg->vaddr + seg->memsz > image->high_vaddr)
            {
                image->high_vaddr = seg->vaddr + seg->memsz;
            }
        }
    }

    if (image->segment_count == 0)
    {
        rt_kprintf("[elf] /%s/%s has no LOAD segments\n", abi, path);
        goto out;
    }

    ret = 0;

out:
    judge_ext4_free_file(&phdr_file);
    return ret;
}

int os_elf_load_from_ext4(const char *abi, const char *path, struct os_elf_image *image)
{
    struct judge_ext4_file header;
    const rt_uint8_t *p;
    rt_uint32_t i;
    int ret = -1;

    if (image == RT_NULL)
    {
        return -1;
    }
    rt_memset(image, 0, sizeof(*image));

    if (judge_ext4_read_file(abi, path, ELF_HDR_SIZE, &header) != 0)
    {
        return -1;
    }
    if (header.size < ELF_HDR_SIZE)
    {
        goto out;
    }

    p = (const rt_uint8_t *)header.data;
    if (p[0] != 0x7f || p[1] != 'E' || p[2] != 'L' || p[3] != 'F')
    {
        goto out;
    }
    if (p[EI_CLASS] != ELFCLASS64 || p[EI_DATA] != ELFDATA2LSB)
    {
        rt_kprintf("[elf] /%s/%s is not little-endian ELF64\n", abi, path);
        goto out;
    }

    image->type = rd16(p + 16);
    image->machine = rd16(p + 18);
    image->entry = rd64(p + 24);
    if (image->type != ET_EXEC && image->type != ET_DYN)
    {
        rt_kprintf("[elf] /%s/%s unsupported ELF type=%u\n", abi, path, image->type);
        goto out;
    }

    if (parse_phdrs(abi, path, p, header.total_size, image) != 0)
    {
        goto out;
    }

    if (image->machine == EM_RISCV)
    {
        for (i = 0; i < image->segment_count; ++i)
        {
            if (load_segment_data(abi, path, &image->segments[i]) != 0)
            {
                os_elf_unload(image);
                goto out;
            }
        }
    }

    ret = 0;

out:
    judge_ext4_free_file(&header);
    return ret;
}

void os_elf_unload(struct os_elf_image *image)
{
    rt_uint32_t i;

    if (image == RT_NULL)
    {
        return;
    }

    for (i = 0; i < image->segment_count; ++i)
    {
        if (image->segments[i].data != RT_NULL)
        {
            rt_free(image->segments[i].data);
            image->segments[i].data = RT_NULL;
        }
    }
    image->segment_count = 0;
}

