int rt_hw_tick_init(void)
{
    /* calculate the tick cycles */
    tick_cycles = CPUTIME_TIMER_FREQ / RT_TICK_PER_SECOND;

    /* Clear the Supervisor-Timer bit in SIE */
    clear_csr(sie, SIP_STIP);

