static int handle_echo_line(const char *line)
{
    const char *cursor = line;
    char token[128];
    int ret;

    ret = copy_first_token(&cursor, token, sizeof(token));
    if (ret <= 0)
    {
        return ret;
    }

    if (str_eq(skip_leading_path_prefix(token), "busybox"))
    {
        ret = copy_first_token(&cursor, token, sizeof(token));
        if (ret <= 0 || !str_eq(token, "echo"))
        {
            return 0;
        }
        print_echo_payload(cursor);
        return 1;
    }

    if (str_eq(token, "echo"))
    {
        print_echo_payload(cursor);
        return 1;
    }

    return 0;
}

static int handle_cd_line(const char *line, char *cwd, rt_size_t cwd_size)
{
    const char *cursor = line;
    char token[128];
    char next_cwd[128];
    int ret;

    ret = copy_first_token(&cursor, token, sizeof(token));
    if (ret <= 0 || !str_eq(token, "cd"))
    {
        return 0;
    }
    ret = copy_first_token(&cursor, token, sizeof(token));
    if (ret <= 0)
    {
        copy_string(cwd, cwd_size, "");
        return 1;
    }
    if (normalize_runner_path(cwd, token, next_cwd, sizeof(next_cwd)) != 0)
    {
        return 1;
    }
    copy_string(cwd, cwd_size, next_cwd);
    rt_kprintf("[runner] script cwd -> /%s\n", cwd[0] == '\0' ? "." : cwd);
    return 1;
}

static int extract_exec_candidate(const char *line, char *candidate, rt_size_t candidate_size)
{
