        ret = copy_first_token(&cursor, token, sizeof(token));
        if (ret <= 0)
        {
            return ret;
        }

        if (str_eq(token, "env") || str_eq(token, "timeout") || str_eq(token, "time") ||
            str_eq(token, "nice") || str_eq(token, "taskset") || str_eq(token, "chrt"))
        {
            continue;
        }
        if (str_eq(token, "cd") || str_eq(token, "echo") || str_eq(token, "export") ||
            str_eq(token, "ulimit") || str_eq(token, "mkdir") || str_eq(token, "rm") ||
            str_eq(token, "cat") || str_eq(token, "if") || str_eq(token, "for") ||
            str_eq(token, "while") || str_eq(token, "then") || str_eq(token, "do"))
        {
            return 0;
        }
        if (token_has_shell_meta(token))
        {
            return 0;
        }

        if (starts_with(token, "./") || starts_with(token, "/") || known_binary_name(token))
        {
            const char *path = skip_leading_path_prefix(token);
            rt_size_t len = 0;

            while (path[len] != '\0')
            {
                if (len + 1 >= candidate_size)
                {
                    return -1;
                }
                candidate[len] = path[len];
                len++;
            }
            candidate[len] = '\0';
            return 1;
        }

        return 0;
    }
}

static int extract_exec_argv(const char *line,
                             char *candidate, rt_size_t candidate_size,
                             char argv[][OS_USER_EXEC_ARG_SIZE],
                             int *argc)
{
    const char *cursor = line;
    char token[128];
    int ret;
    int count;

    for (;;)
    {
        ret = copy_argument_token(&cursor, token, sizeof(token));
        if (ret <= 0)
        {
            return ret;
        }

        if (str_eq(token, "env") || str_eq(token, "timeout") || str_eq(token, "time") ||
            str_eq(token, "nice") || str_eq(token, "taskset") || str_eq(token, "chrt"))
        {
            continue;
        }
        if (str_eq(token, "cd") || str_eq(token, "echo") || str_eq(token, "export") ||
            str_eq(token, "ulimit") || str_eq(token, "mkdir") || str_eq(token, "rm") ||
            str_eq(token, "cat") || str_eq(token, "if") || str_eq(token, "for") ||
            str_eq(token, "while") || str_eq(token, "then") || str_eq(token, "do"))
        {
            return 0;
        }
        if (token_has_shell_meta(token))
        {
            return 0;
        }

        if (starts_with(token, "./") || starts_with(token, "/") || known_binary_name(token))
        {
            const char *path = skip_leading_path_prefix(token);

            copy_string(candidate, candidate_size, path);
            copy_string(argv[0], OS_USER_EXEC_ARG_SIZE, path);
            count = 1;

            while (count < OS_USER_EXEC_ARG_MAX)
            {
                ret = copy_argument_token(&cursor, token, sizeof(token));
                if (ret <= 0)
                {
                    break;
                }
                if (str_eq(token, ">") || str_eq(token, ">>") ||
                    str_eq(token, "<") || str_eq(token, "|") ||
                    token_has_shell_meta(token))
                {
                    return 0;
                }
                copy_string(argv[count], OS_USER_EXEC_ARG_SIZE, token);
                count++;
            }

            *argc = count;
            return 1;
        }

        return 0;
    }
}

static int inspect_elf_candidate_depth_args(const char *abi, const char *path,
                                            const char *cwd,
                                            int run_mode, unsigned int depth,
                                            const char *const argv[],
                                            int argc)
{
    struct os_elf_image image;
    struct os_user_image user_image;
    char exec_path[128];
    char exec_argv[OS_USER_EXEC_ARG_MAX][OS_USER_EXEC_ARG_SIZE];
    const char *exec_argv_ptrs[OS_USER_EXEC_ARG_MAX];
    int exec_argc = 0;
    int executed = 0;
    int built_image = 0;
    int status = 0;
    int i;

    if (os_elf_load_from_ext4(abi, path, &image) != 0)
    {
        rt_kprintf("[runner] executable candidate /%s/%s is not a loadable ELF yet\n", abi, path);
        return 0;
    }

    if (run_mode == RUN_MODE_PREVIEW)
    {
        os_elf_dump_plan(abi, path, &image);
    }
    if (image.machine == 243)
    {
        if (os_user_image_build(&image, &user_image) == 0)
        {
            built_image = 1;
            if (run_mode == RUN_MODE_PREVIEW)
            {
                os_user_image_dump(abi, path, &user_image);
            }
            if (run_mode != RUN_MODE_PREVIEW)
            {
                status = os_user_exec_run_smoke_at_args(abi, path, cwd,
                                                        &user_image,
                                                        argv, argc);
                executed = 1;
            }
        }
        else
        {
            rt_kprintf("[image] failed to prepare user image for /%s/%s\n", abi, path);
        }
    }

    if (built_image)
    {
        os_user_image_destroy(&user_image);
    }
    os_elf_unload(&image);

    if (status == OS_USER_EXEC_STATUS_EXECVE &&
        os_user_exec_take_execve_request(exec_path, sizeof(exec_path),
                                         exec_argv, &exec_argc))
    {
        if (depth >= 4)
        {
            rt_kprintf("[runner] execve chain too deep at /%s/%s\n", abi, exec_path);
            return executed;
        }
        for (i = 0; i < exec_argc && i < OS_USER_EXEC_ARG_MAX; ++i)
        {
            exec_argv_ptrs[i] = exec_argv[i];
        }
        return inspect_elf_candidate_depth_args(abi, skip_leading_path_prefix(exec_path),
                                                cwd, run_mode, depth + 1U,
                                                exec_argv_ptrs, exec_argc);
    }

    return executed;
}

static int inspect_elf_candidate_depth(const char *abi, const char *path,
                                       const char *cwd,
                                       int run_mode, unsigned int depth)
{
    const char *argv[1];

    argv[0] = path;
    return inspect_elf_candidate_depth_args(abi, path, cwd, run_mode,
                                            depth, argv, 1);
}

