int os_user_exec_run_smoke_at_args_stdio(const char *abi, const char *path,
                                         const char *cwd,
                                         const struct os_user_image *image,
                                         const char *const argv[],
                                         int argc,
                                         const char *stdin_path,
                                         const char *stdout_path,
                                         int stdout_append)
{
    struct os_user_page_pool *pool = &g_run_pool;
    rt_uint64_t *root;
    rt_uint64_t user_sp = 0;
    rt_uint64_t kernel_sp;
    rt_uint64_t satp;

    if (image == RT_NULL || image->mapping_count == 0)
    {
        return -1;
    }
    __asm__ volatile("csrr %0, satp" : "=r"(satp));
    if (satp != 0)
    {
