                   (rt_uint32_t)(satp >> 32), (rt_uint32_t)satp);
        return -1;
    }

    rt_memset(pool, 0, sizeof(*pool));
    root = (rt_uint64_t *)alloc_aligned_page(pool);
    if (root == RT_NULL)
    {
        return -1;
    }

    if (map_range_identity(root, pool, 0x0c000000ULL, 0x400000, PTE_R | PTE_W) != 0 ||
        map_range_identity(root, pool, 0x10000000ULL, 0x200000, PTE_R | PTE_W) != 0 ||
        map_kernel_1g_leaf(root, 0x80000000ULL, 0x80000000ULL,
