        map_user_stack(root, pool, &user_sp) != 0)
    {
        rt_kprintf("[user] failed to build smoke page table for /%s/%s\n", abi, path);
        free_page_pool(pool);
        return -1;
    }

    g_current_abi = abi;
    runtime_reset(abi, cwd);
    g_active_root = root;
    g_active_pool = pool;
    g_brk_current = image->high_vaddr;
    g_brk_mapped = page_up(image->high_vaddr);
    g_mmap_next = OS_MMAP_BASE;
    g_user_exec_active = 0;
    g_user_exit_code = -1;
    g_user_syscall_budget = OS_SYSCALL_BUDGET;

    if (save_runner_context(&g_resume_ctx) != 0)
    {
        goto user_returned;
    }

    __asm__ volatile("mv %0, sp" : "=r"(kernel_sp));
    if (runtime_redirect_stdin(stdin_path) != 0)
    {
        rt_kprintf("[user] failed to redirect stdin for /%s/%s\n", abi, path);
        g_current_abi = RT_NULL;
        g_active_root = RT_NULL;
        g_active_pool = RT_NULL;
        free_page_pool(pool);
        return -1;
    }
    if (runtime_redirect_stdout(stdout_path, stdout_append) != 0)
    {
        rt_kprintf("[user] failed to redirect stdout for /%s/%s\n", abi, path);
        g_current_abi = RT_NULL;
        g_active_root = RT_NULL;
        g_active_pool = RT_NULL;
        free_page_pool(pool);
        return -1;
    }
    switch_to_page_table(root);
    if (setup_initial_user_stack(path, argv, argc, image, &user_sp) != 0)
    {
        __asm__ volatile("csrw satp, zero\n"
                         "sfence.vma x0, x0\n"
                         :
                         :
                         : "memory");
        rt_kprintf("[user] failed to build initial stack for /%s/%s\n", abi, path);
        g_current_abi = RT_NULL;
        g_active_root = RT_NULL;
        g_active_pool = RT_NULL;
        free_page_pool(pool);
        return -1;
    }
    g_user_exec_active = 1;
    enter_user_mode(image->entry, user_sp, kernel_sp);

user_returned:
    g_current_abi = RT_NULL;
    g_active_root = RT_NULL;

