static int read_ext4_layout(rt_device_t dev, struct ext4_layout *layout)
{
    rt_uint8_t super[EXT4_SUPER_SIZE];

    if (read_bytes(dev, EXT4_SUPER_OFFSET, super, sizeof(super)) != 0)
    {
        rt_kprintf("[judge] failed to read EXT4 superblock from virtio-blk0\n");
        return -1;
    }
    if (le16(super + 56) != EXT4_MAGIC)
    {
        rt_kprintf("[judge] virtio-blk0 super magic 0x%x is not EXT4\n", le16(super + 56));
        return -1;
    }

    layout->block_size = 1024U << le32(super + 24);
    if (layout->block_size < 1024U || layout->block_size > 4096U)
    {
        rt_kprintf("[judge] unsupported EXT4 block size: %u\n", layout->block_size);
        return -1;
    }

    layout->inodes_per_group = le32(super + 40);
    layout->inode_size = le16(super + 88);
    layout->desc_size = le16(super + 254);
    if (layout->inodes_per_group == 0)
    {
        return -1;
    }
    if (layout->inode_size == 0)
    {
        layout->inode_size = 128;
    }
    if (layout->desc_size < 32 || layout->desc_size > 64)
    {
        layout->desc_size = 32;
    }

    layout->gdt_offset = (layout->block_size == 1024U) ?
                         (2ULL * layout->block_size) : layout->block_size;
    return 0;
}

static int scan_open_ext4_device(rt_device_t dev, const char *directory_name,
                                 const char *script_name)
{
    rt_uint8_t inode[256];
    struct ext4_layout layout;
    rt_uint32_t directory_inode;
    rt_uint32_t script_inode;

    listed_names = 0;
    if (read_ext4_layout(dev, &layout) != 0)
    {
        return 0;
    }
    if (read_inode(dev, &layout, EXT4_ROOT_INODE, inode, sizeof(inode)) != 0)
    {
        rt_kprintf("[judge] failed to read EXT4 root inode\n");
        return 0;
    }

    ext4_trace("[judge] scanning /%s for %s\n", directory_name, script_name);
    directory_inode = scan_inode_directory(dev, inode, layout.block_size, directory_name);
    if (directory_inode == 0)
    {
        ext4_trace("[judge] directory %s not found in EXT4 root\n", directory_name);
        return 0;
    }

    if (read_inode(dev, &layout, directory_inode, inode, sizeof(inode)) != 0)
    {
        rt_kprintf("[judge] failed to read /%s inode %u\n", directory_name, directory_inode);
        return 0;
    }

    listed_names = 0;
    script_inode = scan_inode_directory(dev, inode, layout.block_size, script_name);
    if (script_inode == 0)
    {
        ext4_trace("[judge] %s not found under /%s\n", script_name, directory_name);
        return 0;
    }

    ext4_trace("[judge] found /%s/%s inode %u\n",
               directory_name, script_name, script_inode);
    return 1;
}

int judge_ext4_has_script(const char *directory_name, const char *script_name)
{
    rt_device_t dev;
    int found;

    dev = rt_device_find("virtio-blk0");
    if (dev == RT_NULL)
    {
        rt_kprintf("[judge] virtio-blk0 not found\n");
        return 0;
    }

    if (rt_device_open(dev, RT_DEVICE_OFLAG_RDONLY) != RT_EOK)
    {
        rt_kprintf("[judge] failed to open virtio-blk0 for reading\n");
        return 0;
    }

    found = scan_open_ext4_device(dev, directory_name, script_name);
    rt_device_close(dev);

    return found;
}

int judge_ext4_cache_file(const char *directory_name, const char *path,
                          rt_size_t max_size)
{
    struct judge_ext4_file file;
    rt_size_t i;

    if (directory_name == RT_NULL || path == RT_NULL)
    {
        return -1;
    }
    if (find_cached_file(directory_name, path) != RT_NULL)
    {
        return 0;
    }

    if (judge_ext4_read_file(directory_name, path, max_size, &file) != 0)
    {
        return -1;
    }

    for (i = 0; i < EXT4_CACHE_MAX; ++i)
    {
        if (!file_cache[i].used)
        {
            file_cache[i].used = 1;
            copy_cstring(file_cache[i].directory, sizeof(file_cache[i].directory),
                         directory_name);
            copy_cstring(file_cache[i].path, sizeof(file_cache[i].path), path);
            file_cache[i].data = file.data;
            file_cache[i].size = file.size;
            file_cache[i].total_size = file.total_size;
            ext4_trace("[judge] cached /%s/%s: read=%u total=%u\n",
                       directory_name, path, (rt_uint32_t)file.size,
                       (rt_uint32_t)file.total_size);
            return 0;
        }
    }

    judge_ext4_free_file(&file);
    return -1;
}

int judge_ext4_read_file(const char *directory_name, const char *path,
                         rt_size_t max_size, struct judge_ext4_file *file)
{
    rt_device_t dev;
    struct ext4_layout layout;
    rt_uint8_t inode[256];
    rt_uint64_t total_size;
    rt_size_t read_size;
    rt_uint8_t *data;
    int ret = -1;
    struct ext4_cached_file *cached;

    if (file == RT_NULL || directory_name == RT_NULL || path == RT_NULL)
    {
        return -1;
    }

    file->data = RT_NULL;
